using System.Collections.Concurrent;

namespace Shop
{
    public class OrderCache
    {
        private readonly ConcurrentDictionary<int, Order> _cache = new();

        public void Put(Order order) => _cache[order.Id] = order;

        public Order? Get(int id) => _cache.TryGetValue(id, out var o) ? o : null;

        public void Invalidate(int id) => _cache.TryRemove(id, out _);
    }
}

