namespace Shop
{
    public class OrderService
    {
        private readonly OrderCache _cache;
        private readonly IOrderRepository _repo;

        public OrderService(OrderCache cache, IOrderRepository repo)
        {
            _cache = cache;
            _repo = repo;
        }

        public void UpdateQuantity(int orderId, int lineId, int quantity)
        {
            var order = _repo.Load(orderId);
            order.SetQuantity(lineId, quantity);
            var saved = _repo.Save(order); // Save recalculates totals and returns the persisted order
            _cache.Put(order); // caches the pre-recalculation object instead of 'saved'
        }
    }

    public interface IOrderRepository
    {
        Order Load(int id);
        Order Save(Order order); // returns the order with recalculated totals
    }

    public class Order
    {
        public int Id { get; set; }
        public decimal Total { get; set; }
        public void SetQuantity(int lineId, int quantity) { /* mutates a line; Total is recalculated by the repository on Save */ }
    }
}
